// sizing normalized vs. greatest sales value East or West
WINDOW_MAX(MAX([Sales - 2017 (copy)_3496482225977876536],[Calculation_3496482225977716791]))*
   [5th Axis Metric - East (copy)_3743054306899050499]/WINDOW_MAX(MAX([Calculation_3743054306897076225], [5th Axis Metric - East (copy)_3743054306899050499]))

// we can't just take STR([Profit Ratio]) because that drops our formatting
// this will adjust spacing regardless of the digits of profit ratio
// yes, I could combine 4 and 2, but the 4 is the base spacing
// and 2 is the corretion for the decimal formatting of the percentage
// this also accounts for negative and rounding - what a bear!
// should work for profit ratios up to +/ 9999%
LEFT('    ',4-(
INT(LOG(ROUND(ABS([Calculation_3496482224588271622])*100),10))
+IIF([Calculation_3496482224588271622]<0,1,0)
))

// could be max or min of string value
// if the shipmode for this region, subcat is the max of its 
// group, return that name
{FIXED [Region], [Sub-Category]:
 MAX(IF [Calculation_3496482225310724139]=
        [Profit SUM by SubCat, Region, Ship Mode (copy)_3496482225312239660] THEN
        [Ship Mode]
     END)
}

// By checking the dot calc, we can color by existing/non-existing value and use
// transparent for non-existing and still keep the mark!
NOT ISNULL([Hash Profit Ratio Window (copy)_3496482224871383058])

// randomly generated based on order count so filters will change this.
LEFT('★★★★★',(COUNT([__tableau_internal_object_id__].[Orders_1E29234DEC5A456397669081DF1F1781])%10+1)/2)+
IF COUNT([__tableau_internal_object_id__].[Orders_1E29234DEC5A456397669081DF1F1781])%2 = 1 THEN '☆' ELSE '' END

// sizing normalized vs. greatest sales value East or West
WINDOW_MAX(MAX([Sales - 2017 (copy)_3496482225977876536],[Calculation_3496482225977716791]))*
   [Calculation_3743054306897076225]/WINDOW_MAX(MAX([Calculation_3743054306897076225], [5th Axis Metric - East (copy)_3743054306899050499]))

// This is a hack to give a mark only where there is a deep discount.
// null otherwise on dual axis.
// Therefore, we can levarage borders on our indicator only.
// Conditional Borders! 
IF AVG([Discount])>0.25 THEN 0.97 END

// this calc would return T for sales per order slightly above averages for the whole dataset
SUM(Sales)/COUNTD([Order ID]) > 460
// randomly generated based on order count. filters will change this.
// you can easily change this to something real like
// SUM([Sale]) > [Sales Target Parameter]
//COUNT([Orders])%2 = 1

// use the single mark of on time and move it's label to the center.
// assumes a non-null on-time portion
IF [Calculation_3496482225989066817] THEN 
   {EXCLUDE [Calculation_3496482225989066817]: IF NOT [Calculation_3496482223900286977] THEN '◯' END}
END

// use the single mark of on time and move it's label to the center.
